import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as l}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as c,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as m,a1 as d,C as a}from"./framework-a4c02b8f.js";const f={},u=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/cacc82655b40808cfe36e50eb4f099a6.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),g=d('<hr><p>今夜我也是一个人在深夜里咔嗒咔嗒地敲击着笔记本电脑，但当然谁都会突然感到寂寞。但是，因寂寞而在深夜做出尴尬的行为（突然发布莫名其妙的推文或联系他人），然后第二天后悔，这种情况也并不少见。但也并不至于为了这个而去喝酒的店。</p><p>在那种时候！去城市的牛肉盖饭连锁店或者拉面店看看吧，那里充满了一些寂寞的背影。这些哥哥和大叔们，不知道是下了夜班，还是从早上就开始工作，大家都背负着劳动的十字架，疲惫不堪。这就是社会的现实。生活不只有闪闪发光。而我，也点了一份普通牛肉饭，成为了这个景象的一部分。大家都是寂寞的。</p><p>因为有这样的心情，我久违地去了家系拉面店。在深夜。家系拉面店从早上就开始营业，一直开到很晚，真了不起啊。中野也有很多家系拉面店。</p><p>点了一份拉面，然后找了个座位。从门缝里吹来的风很冷。兴奋的店员们对寒冷毫不在意。柜台上满座皆是：男男男男。明明是深夜却有如此盛况。这就是男人下班后的世界。虽然我完全没有工作过……甚至刚刚醒来。</p><p>趁着这个机会，我倾听着男人们的对话。「看到○○君的Instagram的故事了吗？太酷了！！」，「（可能是某个偶像团体）的○○小姐据说是半个混血！这身材真是犯规！！」。</p><p>真好……典型的深夜拉面店的对话。就像教室里的小淘气团体，只是身体变得更大了。我就是为了听这些话而特意来到胃容量不足以消化那么多食物的家系拉面店的。话说回来，「半个混血」这个词用得也太奇怪了吧。当然，他们并不在乎这么细枝末节的事情。他们脑子里只有眼前的拉面要用什么调料来定制。</p><p>感觉这个世界就应该如此单纯。我感受到了『剧场版Ideon』结尾的那种开悟。正当我陶醉其中时，因为我的拉面准备好了，所以被店员喊到了。</p><p>「小哥哥，要加○○吗？」</p><p>他说得太快，我没听懂！糟糕。家系和二郎系在点菜时需要告诉他们各种喜好和选项。因为太久没来了，我完全忘记了这一点。不知道要加什么……。无可奈何，我试着让他再问一遍……。</p><p>「要加○○吗？」</p><p>不行。还是听不清。再问一次太失礼了。而且，如果他们免费给我加什么的话，最好还是点一下。「拜托了！」我回答道。然后……</p><p>结果，他给我加了饭。碳水化合物加碳水化合物。这是家系拉面店中常见的搭配，但对于食量较少的我来说很困难。这个能吃完吗？不安感涌上心头，虽然刚才还因为缝隙的冷风感到寒冷，但现在却满头大汗。</p><p>结果，不行。既不能吃完饭也不能吃完拉面。如果只有其中一个的话还可以，但是……。因为怕剩下会被店员责备，我在他们不注意的时候，迅速把盘子举起来逃离店铺。真是对不起。因为寂寞而外行人般地来吃拉面，真是不好意思。</p><p>原来还有这种失败的情况啊。在柜台上，男人们还在热烈讨论「Instagram上最性感的女人」。</p><hr><p><img src="'+l+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/b5060ff2956b25aa401e930eaff36426.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【“那种感觉”的展柜】我把“那种感觉”的作品整理在展示柜中了。左边的天使大人的手办实在是太涩了，我用手指遮了一下，但不知怎么的，变成了一种像涩涩的自拍女性经常使用的构图呢。</p></blockquote>',18);function b(x,y){const n=a("ExternalLinkIcon"),p=a("RouterLink");return c(),_("div",null,[i(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第19回／深夜に牛丼チェーン店やラーメン屋へ行く"),o(n)])]),e("blockquote",null,[k,e("p",null,[o(p,{to:"/posts/Translate/nyalra_kb_18.html"},{default:m(()=>[t("【奈亚拉面壁自语】第18回｜你能成为能够准时完成ddl的人吗？【230321】")]),_:1})])]),g])}const V=s(f,[["render",b],["__file","nyalra_kb_19.html.vue"]]);export{V as default};
